## Full Integrated Phase 2+3 Implementation

### 1. Backend (`sedona-architect-backend.js`)

**Features:**
- Upload code
- Analyze code (real issues, metrics, deps)
- Heal code (auto-fix: formatting, fill docs, remove TODOs, AI-based repair if enabled)
- Download healed files

#### Dependencies:
- Node.js
- Python 3 (with `pylint`, `black`, `autopep8`, `flake8`, and `openai` if AI heal enabled)
- JS: `eslint`, `prettier`, `express`, `multer`, `cors`, (optionally) `openai` npm package

#### Install (in project root):
```bash
pip install pylint flake8 autopep8 black
npm i express multer cors eslint prettier openai
```

#### Unified Backend Script:

```js
// File: sedona-architect-backend.js

const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');
const cors = require('cors');
const { Configuration, OpenAIApi } = require("openai"); // Optional for AI heal

const upload = multer({ dest: 'uploads/' });
const app = express();
app.use(cors());
app.use(express.json());

const OPENAI_API_KEY = process.env.OPENAI_API_KEY || null; // supply if using AI healing

let openai = null;
if (OPENAI_API_KEY) {
  const configuration = new Configuration({ apiKey: OPENAI_API_KEY });
  openai = new OpenAIApi(configuration);
}

function detectType(filename) {
  if (filename.endsWith('.py')) return 'python';
  if (filename.endsWith('.js')) return 'javascript';
  return 'unknown';
}

// ... (copy parsePythonDeps, parseJSDeps functions from previous script)

function parsePythonDeps(code) {
  const lines = code.split('\n');
  const imports = [];
  for (let l of lines) {
    let m = l.match(/^\s*import\s+([\w_]+)/);
    if (m) imports.push(m[1]);
    let f = l.match(/^\s*from\s+([\w_]+)/);
    if (f) imports.push(f[1]);
  }
  return Array.from(new Set(imports));
}

function parseJSDeps(code) {
  const imports = [];
  const regex = /(?:import\s+.*?from\s+['"]([^'"]+)['"])|(?:require\(['"]([^'"]+)['"]\))/g;
  let match;
  while ((match = regex.exec(code))) {
    imports.push(match[1] || match[2]);
  }
  return Array.from(new Set(imports));
}

/**
 * Python Analysis and Healing
 */
function analyzeAndHealPython(filePath, originalName, doHeal, cb) {
  fs.readFile(filePath, 'utf8', (err, code) => {
    if (err) return cb(err);

    // Run pylint
    exec(`pylint --output-format=json "${filePath}"`, (error, stdout) => {
      let pylintIssues = [];
      try { pylintIssues = JSON.parse(stdout); } catch (e) {}

      // Run flake8
      exec(`flake8 --format=%(row)d:%(code)s:%(text)s "${filePath}"`, (ferr, fstdout) => {
        const flake8Lines = fstdout.split('\n').filter(Boolean);

        // Compute metrics (reuse from prior)
        const docCoverage = (code.match(/"""/g) || []).length / (code.split('\n').length) * 100;
        const funcCount = (code.match(/def /g) || []).length;
        const complexity = funcCount ? code.split('\n').length / funcCount : code.split('\n').length;
        const testFuncs = (code.match(/def test_/g) || []).length;
        const testCoverage = funcCount ? (testFuncs / funcCount) * 100 : 0;
        const dependencies = parsePythonDeps(code);

        let issues = [];
        for (let issue of pylintIssues) {
          issues.push(`${issue.symbol} [${issue.line}]: ${issue.message}`);
        }
        for (let l of flake8Lines) {
          issues.push(`flake8: ${l}`);
        }
        if (code.includes('TODO')) issues.push('TODO found in code');
        const emptyFuncs = [...code.matchAll(/def (\w+)\s*\([^)]*\):\s*\n\s+pass/g)];
        for (let ef of emptyFuncs) {
          issues.push(`Function '${ef[1]}' is empty`);
        }

        let health = 100 - issues.length * 10 - Math.min(complexity * 2, 30);
        health = Math.max(0, Math.min(100, health));
        const status = health > 80 ? 'optimized' : (health > 60 ? 'evolved' : (health > 40 ? 'healing' : 'broken'));

        // HEALING!
        function autoHealPython(cb2) {
          // 1. Remove TODOs
          let newCode = code.replace(/# *TODO.*/g, '');
          // 2. Fill empty functions with docstrings
          newCode = newCode.replace(/def (\w+)\s*\([^)]*\):\s*\n\s+pass/g, (m, fn) =>
            `def ${fn}():\n    """Auto-generated docstring."""\n    pass`);
          // 3. Format with autopep8 or black
          fs.writeFile(filePath, newCode, (err) => {
            if (err) return cb2(err);
            exec(`autopep8 --in-place "${filePath}"`, (err) => {
              fs.readFile(filePath, 'utf8', (err, fixedCode) => {
                if (err) return cb2(err);
                cb2(null, fixedCode);
              });
            });
          });
        }

        function aiHealPython(cb2) {
          if (!openai) return cb2(new Error('OpenAI key not set'));
          openai.createChatCompletion({
            model: "gpt-4",
            messages: [
              { role: "system", content: "You are a professional Python code fixer. Clean up the following code, fix all lint, doc, and empty function issues. Output only the fixed code." },
              { role: "user", content: code }
            ],
            max_tokens: 2048,
          }).then(resp => {
            const healed = resp.data.choices[0].message.content;
            cb2(null, healed);
          }).catch(cb2);
        }

        // Run healing if requested
        if (doHeal) {
          // Try auto-heal, then (optionally) AI heal
          autoHealPython((err, fixedCode) => {
            if (err || !fixedCode) return cb(err || new Error("Autoheal failed"));
            // Optionally run AI heal:
            if (openai) {
              aiHealPython((err2, aiCode) => {
                cb(null, {
                  id: path.basename(filePath),
                  name: originalName.replace('.py',''),
                  type: 'python',
                  health, status, complexity, docCoverage, testCoverage, issues, dependencies,
                  healedCode: aiCode || fixedCode
                });
              });
            } else {
              cb(null, {
                id: path.basename(filePath),
                name: originalName.replace('.py',''),
                type: 'python',
                health, status, complexity, docCoverage, testCoverage, issues, dependencies,
                healedCode: fixedCode
              });
            }
          });
        } else {
          cb(null, {
            id: path.basename(filePath),
            name: originalName.replace('.py',''),
            type: 'python',
            health, status, complexity, docCoverage, testCoverage, issues, dependencies
          });
        }
      });
    });
  });
}

/**
 * JavaScript Analysis and Healing
 */
function analyzeAndHealJS(filePath, originalName, doHeal, cb) {
  fs.readFile(filePath, 'utf8', (err, code) => {
    if (err) return cb(err);

    exec(`npx eslint --format json "${filePath}"`, (error, stdout) => {
      let eslintIssues = [];
      try { eslintIssues = JSON.parse(stdout)[0]?.messages || []; } catch (e) {}

      const docCoverage = (code.match(/\/\*\*/g) || []).length / (code.split('\n').length) * 100;
      const funcCount = (code.match(/function\s+\w+/g) || []).length + (code.match(/const\s+\w+\s*=\s*\(/g) || []).length;
      const complexity = funcCount ? code.split('\n').length / funcCount : code.split('\n').length;
      const testCalls = (code.match(/\btest\(/g) || []).length + (code.match(/\bdescribe\(/g) || []).length;
      const testCoverage = funcCount ? (testCalls / funcCount) * 100 : 0;
      const dependencies = parseJSDeps(code);

      const issues = [];
      for (let issue of eslintIssues) {
        issues.push(`${issue.ruleId || "eslint"} [${issue.line}]: ${issue.message}`);
      }
      if (code.includes('TODO')) issues.push('TODO found in code');
      const emptyFuncs = [...code.matchAll(/function (\w+)\s*\([^)]*\)\s*{\s*}/g)];
      for (let ef of emptyFuncs) {
        issues.push(`Function '${ef[1]}' is empty`);
      }
      let health = 100 - issues.length * 10 - Math.min(complexity * 2, 30);
      health = Math.max(0, Math.min(100, health));
      const status = health > 80 ? 'optimized' : (health > 60 ? 'evolved' : (health > 40 ? 'healing' : 'broken'));

      // HEALING
      function autoHealJS(cb2) {
        let newCode = code.replace(/\/\/ *TODO.*/g, '');
        // Fill empty functions with docstrings
        newCode = newCode.replace(/function (\w+)\s*\([^)]*\)\s*{\s*}/g, (m, fn) =>
          `function ${fn}() {\n  /** Auto-generated doc */\n}`);
        // Format with prettier
        fs.writeFile(filePath, newCode, (err) => {
          if (err) return cb2(err);
          exec(`npx prettier --write "${filePath}"`, (err) => {
            fs.readFile(filePath, 'utf8', (err, fixedCode) => {
              if (err) return cb2(err);
              cb2(null, fixedCode);
            });
          });
        });
      }
      function aiHealJS(cb2) {
        if (!openai) return cb2(new Error('OpenAI key not set'));
        openai.createChatCompletion({
          model: "gpt-4",
          messages: [
            { role: "system", content: "You are a professional JavaScript code fixer. Clean up the following code, fix all lint, doc, and empty function issues. Output only the fixed code." },
            { role: "user", content: code }
          ],
          max_tokens: 2048,
        }).then(resp => {
          const healed = resp.data.choices[0].message.content;
          cb2(null, healed);
        }).catch(cb2);
      }
      if (doHeal) {
        autoHealJS((err, fixedCode) => {
          if (err || !fixedCode) return cb(err || new Error("Autoheal failed"));
          if (openai) {
            aiHealJS((err2, aiCode) => {
              cb(null, {
                id: path.basename(filePath),
                name: originalName.replace('.js',''),
                type: 'javascript',
                health, status, complexity, docCoverage, testCoverage, issues, dependencies,
                healedCode: aiCode || fixedCode
              });
            });
          } else {
            cb(null, {
              id: path.basename(filePath),
              name: originalName.replace('.js',''),
              type: 'javascript',
              health, status, complexity, docCoverage, testCoverage, issues, dependencies,
              healedCode: fixedCode
            });
          }
        });
      } else {
        cb(null, {
          id: path.basename(filePath),
          name: originalName.replace('.js',''),
          type: 'javascript',
          health, status, complexity, docCoverage, testCoverage, issues, dependencies
        });
      }
    });
  });
}

/**
 * Main /analyze endpoint, with heal option
 */
app.post('/analyze', upload.array('files'), (req, res) => {
  const files = req.files;
  const doHeal = req.body.heal === 'true' || req.body.heal === true;
  if (!files || files.length === 0) return res.status(400).json({ error: "No files uploaded" });

  let modules = [];
  let completed = 0;

  files.forEach(file => {
    const fileType = detectType(file.originalname);
    if (fileType === 'python') {
      analyzeAndHealPython(file.path, file.originalname, doHeal, (err, result) => {
        completed++;
        if (!err && result) modules.push(result);
        if (completed === files.length) {
          // Cleanup
          files.forEach(f => fs.unlink(f.path,()=>{}));
          res.json({ modules });
        }
      });
    } else if (fileType === 'javascript') {
      analyzeAndHealJS(file.path, file.originalname, doHeal, (err, result) => {
        completed++;
        if (!err && result) modules.push(result);
        if (completed === files.length) {
          // Cleanup
          files.forEach(f => fs.unlink(f.path,()=>{}));
          res.json({ modules });
        }
      });
    } else {
      completed++;
      if (completed === files.length) {
        files.forEach(f => fs.unlink(f.path,()=>{}));
        res.json({ modules });
      }
    }
  });
});

const PORT = 4040;
app.listen(PORT, () => {
  console.log(`Sedona Sovereign Architect backend running at http://localhost:${PORT}`);
});
