### 2. Frontend (React) Key Integrations

**You already have the dashboard. Here’s how you integrate:**

#### File Upload and Analyze/Heal

```jsx
// Add this to your Sedona dashboard (e.g. in the header or a modal)
const [modules, setModules] = useState([]);
const [files, setFiles] = useState([]);
const [isHealing, setIsHealing] = useState(false);

function handleUpload(e) {
  setFiles(Array.from(e.target.files));
}

async function runAnalysis(heal = false) {
  setIsHealing(true);
  const form = new FormData();
  files.forEach(file => form.append('files', file));
  form.append('heal', heal ? 'true' : 'false');
  const res = await fetch('http://localhost:4040/analyze', {
    method: 'POST',
    body: form,
  });
  const data = await res.json();
  setModules(data.modules);
  setIsHealing(false);
}

// in your JSX
<input type="file" multiple accept=".py,.js" onChange={handleUpload} />
<button onClick={() => runAnalysis(false)}>Analyze Only</button>
<button onClick={() => runAnalysis(true)}>Analyze + Heal</button>
```

- Use `modules` state to populate your dashboard Module grid, health, issues, healing history, etc.
- Display a modal or download button to let users get their healed code (available as `healedCode` property in result).

