  );
  // Add missing docstrings for top-level defs/classes
  healed = healed.replace(
    /^(def \w+\(.*\):\n)( {4}[^\s])/gm,
    (m, def, nextLine) => `${def}    """TODO: Add docstring."""\n${nextLine}`
  );
