```js
async function runAllProjectTests(modulesState) {
  // Save all code files to temp dir
  const tmpDir = './tmp_heal_run';
  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir);
  for (let m of modulesState) {
    fs.writeFileSync(path.join(tmpDir, m.name), m.code);
  }
  // Run pytest and parse results
  let totalTests = 0, passedTests = 0;
  try {
    const result = execSync(`pytest --maxfail=5 --disable-warnings --tb=short`, { cwd: tmpDir, encoding: 'utf8' });
    const match = result.match(/(\d+) passed.*?(\d+) failed/);
    if (match) {
      passedTests = parseInt(match[1]);
      totalTests = passedTests + parseInt(match[2]);
    }
  } catch (e) {
    // Parse test output even if failures
    const out = e.stdout || '';
    const match = out.match(/(\d+) passed.*?(\d+) failed/);
    if (match) {
      passedTests = parseInt(match[1]);
      totalTests = passedTests + parseInt(match[2]);
    }
  }
  // Clean up
  fs.rmSync(tmpDir, { recursive: true, force: true });
  return { totalTests, passedTests };
}
