    { id: "fix_missing_args", apply: fixMissingArgs },
    { id: "rename_wrong_symbols", apply: renameWrongSymbols },
    { id: "fill_missing_stubs", apply: fillMissingStubs }
  ];
  // Prioritize learned patterns
  const frequent = patterns.reduce((acc, p) => { acc[p.id] = (acc[p.id]||0)+1; return acc; }, {});
  healingStrategies = healingStrategies.sort((a,b)=> (frequent[b.id]||0) - (frequent[a.id]||0));
  let history = [];
  let loop = 0;
  let didHeal = true;
  let modulesState = modules.map(m => ({ ...m }));
  let bestTestPass = 0;
  let bestModules = JSON.parse(JSON.stringify(modulesState)); // deep copy

  while (loop < maxCycles && didHeal) {
    didHeal = false;
    let roundLog = [];
    // Heal modules as before
    for (let m of modulesState) {
      let healedCode = m.code;
      let healLog = [];
      for (let strat of healingStrategies) {
        const { fixed, log } = strat.apply(healedCode, modulesState, null, m);
        if (fixed && fixed !== healedCode) {
          healLog.push({ strategy: strat.id, details: log });
          healedCode = fixed;
          logPattern({ id: strat.id, details: log, ts: Date.now() });
          didHeal = true;
        }
      }
      // Format and lint
      if (m.type === 'python') {
        fs.writeFileSync(m.name, healedCode);
        try {
          execSync(`autoflake --in-place --remove-unused-variables --remove-all-unused-imports "${m.name}"`);
          execSync(`autopep8 --in-place "${m.name}"`);
          execSync(`black "${m.name}"`);
        } catch (e) {}
        healedCode = fs.readFileSync(m.name, 'utf8');
      } else if (m.type === 'javascript') {
        fs.writeFileSync(m.name, healedCode);
        try {
          execSync(`npx eslint --fix "${m.name}"`);
          execSync(`npx prettier --write "${m.name}"`);
        } catch (e) {}
        healedCode = fs.readFileSync(m.name, 'utf8');
      }
      m.code = healedCode;
      m.healingHistory = (m.healingHistory || []).concat(healLog);
      roundLog.push({ module: m.name, healLog });
    }
    // --- NEW: Run functional tests ---
    let { totalTests, passedTests } = await runAllPythonTests(modulesState);
    // --- Learning priority ---
    if (passedTests > bestTestPass) {
      bestTestPass = passedTests;
      bestModules = JSON.parse(JSON.stringify(modulesState));
      healingStrategies.forEach(strat => logPattern({ id: strat.id, improvedTests: true, loop }));
    } else {
      healingStrategies.forEach(strat => logPattern({ id: strat.id, improvedTests: false, loop }));
    }
    history.push({ loop, passedTests, totalTests, roundLog });
    loop++;
  }
  return { modules: bestModules, history, patterns: loadPatterns() };
}

