### Example: Puppeteer Automation to ChatGPT

Here’s a **simplified (non-headless, for testing) version** that opens ChatGPT, types your prompt, and grabs the answer.

```js
const puppeteer = require('puppeteer');

async function askChatGPTInBrowser(promptText) {
  const browser = await puppeteer.launch({ headless: false }); // set to true for invisible
  const page = await browser.newPage();

  // Go to ChatGPT (you must be logged in already in this browser profile)
  await page.goto('https://chat.openai.com/', { waitUntil: 'networkidle2' });

  // Wait for the prompt box
  await page.waitForSelector('textarea');
  await page.type('textarea', promptText);

  // Press Enter to send
  await page.keyboard.press('Enter');

  // Wait for the answer to appear (ChatGPT typing animation)
  await page.waitForSelector('.markdown', { timeout: 120000 }); // Wait up to 2 mins

  // Get the answer text
  const answer = await page.evaluate(() => {
    // Get all messages, return the last one (ChatGPT's response)
    const messages = Array.from(document.querySelectorAll('.markdown'));
    return messages.length > 0 ? messages[messages.length - 1].innerText : '';
  });

  // Optionally, close browser
  // await browser.close();

  return answer;
}

// Usage example:
