const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const cors = require('cors');
const { Graph } = require('graphlib');
const puppeteer = require('puppeteer');

const upload = multer({ dest: 'uploads/' });
const app = express();
app.use(cors());
app.use(express.json());

const META_PATTERN_LOG = 'meta_pattern_log.json';
function logPattern(pattern) {
  let data = [];
  try { data = JSON.parse(fs.readFileSync(META_PATTERN_LOG)); } catch {}
  data.push(pattern);
  fs.writeFileSync(META_PATTERN_LOG, JSON.stringify(data, null, 2));
}
function loadPatterns() {
  let data = [];
  try { data = JSON.parse(fs.readFileSync(META_PATTERN_LOG)); } catch {}
  return data;
}

function detectType(filename) {
  if (filename.endsWith('.py')) return 'python';
  if (filename.endsWith('.js')) return 'javascript';
  return 'unknown';
}
function parsePythonSymbolsAndDeps(code) {
  const imports = [];
  const symbols = [];
  const lines = code.split('\n');
  for (let l of lines) {
    let m = l.match(/^\s*import\s+([\w_]+)/);
    if (m) imports.push(m[1]);
    let f = l.match(/^\s*from\s+([\w_]+)/);
    if (f) imports.push(f[1]);
    let func = l.match(/^\s*def\s+(\w+)\s*\(([^)]*)\)/);
