// --- Real Healing strategies ---
function healPython(code) {
  let healed = code.replace(/# *TODO.*/g, '');
  healed = healed.replace(
    /def (\w+)\s*\(([^)]*)\):\s*\n\s+pass/g,
    (m, fn, args) => `def ${fn}(${args}):\n    """Auto-generated docstring."""\n    raise NotImplementedError()`
  );
  healed = healed.replace(
    /^(def \w+\(.*\):\n)( {4}[^\s])/gm,
