app.post('/analyze', upload.array('files'), async (req, res) => {
  const files = req.files;
  if (!files || files.length === 0) return res.status(400).json({ error: "No files uploaded" });
  let modules = [];
  let graph = new Graph();
  for (let file of files) {
    const code = fs.readFileSync(file.path, 'utf8');
    let imports, symbols;
    if (detectType(file.originalname) === 'python') {
      ({ imports, symbols } = parsePythonSymbolsAndDeps(code));
    } else {
      ({ imports, symbols } = parseJSSymbolsAndDeps(code));
    }
    modules.push({
      id: file.filename,
      name: file.originalname,
      type: detectType(file.originalname),
      code,
      imports,
      symbols,
      status: 'unprocessed',
      healingHistory: []
    });
    graph.setNode(file.originalname, { type: detectType(file.originalname), symbols });
    for (let dep of imports) graph.setEdge(file.originalname, dep);
  }
  const { modules: healedModules, history, patterns } = await continuousSelfHeal(modules, 20);
  files.forEach(f => fs.unlink(f.path,()=>{}));
  res.json({
    projectGraph: graph.nodes().map(n => ({
      name: n,
      type: graph.node(n).type,
      symbols: graph.node(n).symbols,
      imports: modules.find(m=>m.name===n)?.imports || []
    })),
    modules: healedModules.map(m => ({
      name: m.name,
      type: m.type,
      imports: m.imports,
      symbols: m.symbols,
      healedCode: m.code,
      healingHistory: m.healingHistory
    })),
    healingLoops: history,
    patterns
  });
});

