            round_log.append({'module': m['name'], 'heal_log': heal_log})
        res = run_all_pytest(modules_state)
        passed_tests = res['passed_tests']
        total_tests = res['total_tests']
        if passed_tests > best_test_pass:
            best_test_pass = passed_tests
            best_modules = json.loads(json.dumps(modules_state))
            for strat in healing_strategies:
