    def __init__(self):
        self.logger = logging.getLogger('FunctionAnalyzer')

    def analyze_function_safety(self, func_code: str) -> Dict[str, Any]:
        risks = []
        has_self_test = False
        callback_methods = []
        try:
            tree = ast.parse(func_code)
