        return complexity

    def extract_function_metadata(self, func_code: str) -> Dict[str, Any]:
        """Extract metadata from function code"""
        try:
            tree = ast.parse(func_code)
            functions = []

            for node in ast.walk(tree):
                if isinstance(node, ast.FunctionDef):
                    functions.append({
                        'name': node.name,
                        'args': [arg.arg for arg in node.args.args],
                        'docstring': ast.get_docstring(node),
                        'returns': node.returns is not None
                    })

            return {'functions': functions}
        except Exception as e:
            return {'functions': [], 'error': str(e)}

class ModuleEvolver:
    """Evolves and enhances adopted modules"""

    def __init__(self, sovereign_core):
        self.sovereign_core = sovereign_core
        self.logger = logging.getLogger('ModuleEvolver')
        self.evolution_patterns = {}

    def enhance_module(self, module_name: str, usage_data: Dict) -> Optional[str]:
        """Generate enhanced version of module based on usage patterns"""
        try:
            if module_name not in self.sovereign_core.runtime_modules:
                return None

            module_data = self.sovereign_core.runtime_modules[module_name]
            module = module_data['module']
            enhancements = []

            # Add logging if heavily used
            if usage_data.get('call_count', 0) > 100:
                enhancements.append(self._add_logging_wrapper())

            # Add caching for pure functions
            if usage_data.get('pure_function', False):
                enhancements.append(self._add_caching_wrapper())

            # Add error handling
            if usage_data.get('error_rate', 0) > 0.1:
                enhancements.append(self._add_error_handling())

            # Add performance monitoring
            if usage_data.get('call_count', 0) > 50:
                enhancements.append(self._add_performance_monitoring())

            if enhancements:
                enhanced_code = self._apply_enhancements(module_data, enhancements)
                return enhanced_code

            return None
        except Exception as e:
            self.logger.error(f"Enhancement failed for {module_name}: {e}")
            return None

    def _add_logging_wrapper(self) -> str:
        return '''
def add_logging_wrapper(func):
    import functools
    import logging

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        logger = logging.getLogger(f'Runtime.{func.__name__}')
        logger.info(f'Calling {func.__name__} with args: {args[:3]}...')
        start_time = time.time()
        result = func(*args, **kwargs)
        duration = time.time() - start_time
        logger.info(f'{func.__name__} completed in {duration:.4f}s')
        return result
    return wrapper
'''

    def _add_caching_wrapper(self) -> str:
        return '''
def add_caching_wrapper(func):
    import functools
    import time

    cache = {}
    cache_stats = {'hits': 0, 'misses': 0}

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        key = str(args) + str(sorted(kwargs.items()))
        if key not in cache:
            cache[key] = {'result': func(*args, **kwargs), 'timestamp': time.time()}
            cache_stats['misses'] += 1
        else:
            cache_stats['hits'] += 1
        return cache[key]['result']

    wrapper.cache_stats = cache_stats
    wrapper.clear_cache = lambda: cache.clear()
    return wrapper
'''

    def _add_error_handling(self) -> str:
        return '''
def add_error_handling(func):
    import functools
    import logging

    error_stats = {'error_count': 0, 'last_error': None}

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception as e:
            logger = logging.getLogger(f'Runtime.{func.__name__}')
            logger.error(f'Error in {func.__name__}: {e}')
            error_stats['error_count'] += 1
            error_stats['last_error'] = str(e)
            return None

    wrapper.error_stats = error_stats
    return wrapper
'''

    def _add_performance_monitoring(self) -> str:
        return '''
def add_performance_monitoring(func):
    import functools
    import time

    perf_stats = {'call_count': 0, 'total_time': 0, 'avg_time': 0, 'min_time': float('inf'), 'max_time': 0}

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start_time = time.time()
        result = func(*args, **kwargs)
        duration = time.time() - start_time

        perf_stats['call_count'] += 1
        perf_stats['total_time'] += duration
        perf_stats['avg_time'] = perf_stats['total_time'] / perf_stats['call_count']
        perf_stats['min_time'] = min(perf_stats['min_time'], duration)
        perf_stats['max_time'] = max(perf_stats['max_time'], duration)

        return result

    wrapper.perf_stats = perf_stats
    return wrapper
'''

    def _apply_enhancements(self, module_data: Dict, enhancements: List[str]) -> str:
        """Apply enhancements to module code"""
        enhanced_code = module_data.get('code', '')
        for enhancement in enhancements:
            enhanced_code = enhancement + '\n' + enhanced_code
        return enhanced_code

class RuntimeIntegrator:
    """Integrates modules into the runtime environment"""

    def __init__(self, sovereign_core):
        self.sovereign_core = sovereign_core
        self.logger = logging.getLogger('RuntimeIntegrator')
        self.namespace = {}
        self.integration_futures = {}

    async def integrate_module_async(self, module_name: str, module_code: str, 
                                   metadata: ModuleMetadata) -> bool:
        """Async version of module integration"""
        return await asyncio.get_event_loop().run_in_executor(
            None, self.integrate_module, module_name, module_code, metadata
        )

    def integrate_module(self, module_name: str, module_code: str, metadata: ModuleMetadata) -> bool:
        """Integrate module into runtime with self-testing"""
        try:
            # Create module spec
            spec = importlib.util.spec_from_loader(module_name, loader=None)
            module = importlib.util.module_from_spec(spec)

            # Execute module code in controlled environment
            safe_globals = {
                '__builtins__': {
                    'len': len, 'str': str, 'int': int, 'float': float, 'bool': bool,
                    'list': list, 'dict': dict, 'tuple': tuple, 'set': set,
                    'min': min, 'max': max, 'sum': sum, 'all': all, 'any': any,
                    'enumerate': enumerate, 'zip': zip, 'range': range,
                    'print': print, 'abs': abs, 'round': round, 'time': time
                }
            }

            exec(module_code, safe_globals, module.__dict__)

            # Run self-test if available
            if metadata.has_self_test:
                test_passed = self._run_module_self_test(module, module_name)
                if not test_passed:
                    self.logger.warning(f"Module {module_name} failed self-test")
                    return False

            # Store in runtime modules
            self.sovereign_core.runtime_modules[module_name] = {
                'module': module,
                'code': module_code,
                'metadata': metadata,
                'usage_stats': {
                    'call_count': 0, 
                    'error_count': 0, 
                    'last_used': time.time(),
                    'integrated_at': time.time(),
                    'last_evolved': 0
                }
            }

            # Make functions available to sovereign core
            self._expose_module_functions(module_name, module)

            # Register callbacks if available
            self._register_module_callbacks(module_name, module, metadata)

            self.logger.info(f"Successfully integrated module: {module_name}")
            return True

        except Exception as e:
            self.logger.error(f"Failed to integrate module {module_name}: {e}")
            return False

    def _run_module_self_test(self, module, module_name: str) -> bool:
        """Run module self-test"""
        try:
            # Look for test function
            test_func = None
            for attr_name in dir(module):
                if attr_name == 'test' or attr_name.startswith('self_test'):
                    test_func = getattr(module, attr_name)
                    break

            if test_func and callable(test_func):
                result = test_func()
                return result is not False  # Consider None as passed

            return True  # No test function found, assume passed

        except Exception as e:
            self.logger.error(f"Self-test failed for {module_name}: {e}")
            return False

    def _register_module_callbacks(self, module_name: str, module, metadata: ModuleMetadata):
        """Register module callbacks"""
        if hasattr(self.sovereign_core, 'callback_manager'):
            for callback_name in metadata.callback_methods:
                if hasattr(module, callback_name):
                    callback_func = getattr(module, callback_name)
                    callback = ModuleCallback(module_name, callback_func)
                    self.sovereign_core.callback_manager.register_callback(callback)

    def _expose_module_functions(self, module_name: str, module):
        """Expose module functions to sovereign core"""
        for attr_name in dir(module):
            if not attr_name.startswith('_'):
                attr = getattr(module, attr_name)
                if callable(attr):
                    # Wrap function with usage tracking
                    wrapped_func = self._wrap_with_tracking(module_name, attr_name, attr)
                    setattr(self.sovereign_core, f"{module_name}_{attr_name}", wrapped_func)

    def _wrap_with_tracking(self, module_name: str, func_name: str, func: Callable):
        """Wrap function with usage tracking"""
        def tracked_wrapper(*args, **kwargs):
            try:
                # Update usage stats
                stats = self.sovereign_core.runtime_modules[module_name]['usage_stats']
                stats['call_count'] += 1
                stats['last_used'] = time.time()

                result = func(*args, **kwargs)
                return result
            except Exception as e:
                stats['error_count'] += 1
                self.logger.error(f"Error in {module_name}.{func_name}: {e}")
                raise

        return tracked_wrapper

class CallbackManager:
    """Manages module callbacks and scheduling"""

    def __init__(self, sovereign_core):
        self.sovereign_core = sovereign_core
        self.logger = logging.getLogger('CallbackManager')
        self.callbacks = {}
        self.scheduled_callbacks = []
        self.executor = ThreadPoolExecutor(max_workers=4)

    def register_callback(self, callback: ModuleCallback):
        """Register a module callback"""
        self.callbacks[f"{callback.module_name}_{callback.callback_func.__name__}"] = callback

        if callback.schedule_interval:
            self.scheduled_callbacks.append(callback)

    def execute_callbacks(self):
        """Execute scheduled callbacks"""
        current_time = time.time()

        for callback in self.scheduled_callbacks:
            if (callback.enabled and 
                current_time - callback.last_executed >= callback.schedule_interval):

                # Check trigger condition if exists
                if callback.trigger_condition and not callback.trigger_condition():
                    continue

                # Execute callback
                try:
                    self.executor.submit(self._execute_callback, callback)
                    callback.last_executed = current_time
                    callback.execution_count += 1
                except Exception as e:
                    self.logger.error(f"Failed to execute callback {callback.module_name}: {e}")

    def _execute_callback(self, callback: ModuleCallback):
        """Execute individual callback"""
        try:
            callback.callback_func()
        except Exception as e:
            self.logger.error(f"Callback execution failed: {e}")

class RuntimeSignalLoop:
    """Handles runtime signals and control flow"""

    def __init__(self, sovereign_core):
        self.sovereign_core = sovereign_core
        self.logger = logging.getLogger('RuntimeSignalLoop')
        self.signal_queue = queue.Queue()
        self.active = True
        self.signal_handlers = {
            SignalType.SHUTDOWN: self._handle_shutdown,
            SignalType.PAUSE: self._handle_pause,
            SignalType.RESUME: self._handle_resume,
            SignalType.EVOLVE: self._handle_evolve,
            SignalType.CLEANUP: self._handle_cleanup,
            SignalType.STATUS_CHECK: self._handle_status_check
        }

    def send_signal(self, signal: RuntimeSignal):
        """Send a signal to the runtime"""
        self.signal_queue.put(signal)

    def process_signals(self):
        """Process pending signals"""
        while not self.signal_queue.empty():
            try:
                signal = self.signal_queue.get_nowait()
                handler = self.signal_handlers.get(signal.signal_type)

                if handler:
                    handler(signal)

                if signal.callback:
                    signal.callback(signal)

            except queue.Empty:
                break
            except Exception as e:
                self.logger.error(f"Signal processing error: {e}")

    def _handle_shutdown(self, signal: RuntimeSignal):
        """Handle shutdown signal"""
        self.logger.info("Received shutdown signal")
        self.active = False
        if hasattr(self.sovereign_core, 'dynamic_modules'):
            self.sovereign_core.dynamic_modules.stop()

    def _handle_pause(self, signal: RuntimeSignal):
        """Handle pause signal"""
        self.logger.info("Received pause signal")
        if hasattr(self.sovereign_core, 'dynamic_modules'):
            self.sovereign_core.dynamic_modules.processing_active = False

    def _handle_resume(self, signal: RuntimeSignal):
        """Handle resume signal"""
        self.logger.info("Received resume signal")
        if hasattr(self.sovereign_core, 'dynamic_modules'):
            self.sovereign_core.dynamic_modules.processing_active = True

    def _handle_evolve(self, signal: RuntimeSignal):
        """Handle evolve signal"""
        module_name = signal.data.get('module_name') if signal.data else None
        if module_name and hasattr(self.sovereign_core, 'dynamic_modules'):
            self.sovereign_core.dynamic_modules._evolve_specific_module(module_name)

    def _handle_cleanup(self, signal: RuntimeSignal):
        """Handle cleanup signal"""
        self.logger.info("Received cleanup signal")
        if hasattr(self.sovereign_core, 'dynamic_modules'):
            self.sovereign_core.dynamic_modules._cleanup_unused_modules()

    def _handle_status_check(self, signal: RuntimeSignal):
        """Handle status check signal"""
        if hasattr(self.sovereign_core, 'dynamic_modules'):
            status = self.sovereign_core.dynamic_modules.get_system_status()
            self.logger.info(f"System status: {status}")

class DynamicModuleManager:
    """Main manager for dynamic module integration"""

    def __init__(self, sovereign_core):
        self.sovereign_core = sovereign_core
        self.logger = logging.getLogger('DynamicModuleManager')

        # Initialize components
        self.analyzer = FunctionAnalyzer()
        self.evolver = ModuleEvolver(sovereign_core)
        self.integrator = RuntimeIntegrator(sovereign_core)
        self.signal_loop = RuntimeSignalLoop(sovereign_core)

        # Add callback manager to sovereign core
        self.sovereign_core.callback_manager = CallbackManager(sovereign_core)

        # Module tracking
        self.pending_modules = {}
        self.module_statuses = {}
        self.integration_futures = {}

        # Background processing
        self.processing_thread = threading.Thread(target=self._background_processor, daemon=True)
        self.processing_active = True

        # Usage enforcement
        self.usage_check_interval = 600  # 10 minutes
        self.last_usage_check = time.time()

        # Add runtime modules storage to sovereign core
        if not hasattr(sovereign_core, 'runtime_modules'):
            sovereign_core.runtime_modules = {}

    def start(self):
        """Start the dynamic module manager"""
        self.logger.info("Starting Dynamic Module Manager...")
        self.processing_thread.start()

    def stop(self):
        """Stop the dynamic module manager"""
        self.processing_active = False
        self.signal_loop.active = False
        self.processing_thread.join()
        self.sovereign_core.callback_manager.executor.shutdown(wait=True)

    def receive_module(self, module_code: str, metadata: ModuleMetadata, 
                      await_integration: bool = False) -> Union[str, tuple]:
        """Receive a module from another AI with optional await integration"""
        module_id = hashlib.md5(f"{metadata.module_name}_{metadata.timestamp}".encode()).hexdigest()

        # Update metadata with analysis results
        analysis = self.analyzer.analyze_function_safety(module_code)
        metadata.has_self_test = analysis.get('has_self_test', False)
        metadata.callback_methods = analysis.get('callback_methods', [])

        self.pending_modules[module_id] = {
            'code': module_code,
            'metadata': metadata,
            'received_at': time.time()
        }

        self.module_statuses[module_id] = ModuleStatus.PENDING

        if await_integration:
            # Create future for integration result
            future = asyncio.Future()
            self.integration_futures[module_id] = future

        self.logger.info(f"Received module {metadata.module_name} from {metadata.source_ai}")

        if await_integration:
            return module_id, future
        return module_id

    def get_module_status(self, module_id: str) -> ModuleStatus:
