    def _background_processor(self):
        """Background thread for processing modules"""
        self.start_time = time.time()

        while self.processing_active and self.signal_loop.active:
            try:
                # Process signals first
                self.signal_loop.process_signals()

                # Process pending modules
                self._process_pending_modules()

                # Execute callbacks
                self.sovereign_core.callback_manager.execute_callbacks()

                # Check for unused modules
                self._check_unused_modules()

                # Evolve existing modules
                self._evolve_existing_modules()

                time.sleep(1)  # Process every second

            except Exception as e:
                self.logger.error(f"Background processor error: {e}")

    def _process_pending_modules(self):
        """Process pending modules"""
        for module_id, module_data in list(self.pending_modules.items()):
            if self.module_statuses[module_id] == ModuleStatus.PENDING:
                self._process_single_module(module_id, module_data)

    def _process_single_module(self, module_id: str, module_data: Dict):
        """Process a single module"""
        try:
            # Update status
            self.module_statuses[module_id] = ModuleStatus.ANALYZING

            # Analyze safety
            safety_analysis = self.analyzer.analyze_function_safety(module_data['code'])

            if not safety_analysis['safe']:
                self.logger.warning(f"Module {module_id} failed safety check: {safety_analysis['risks']}")
                self.module_statuses[module_id] = ModuleStatus.FAILED
                self._complete_integration_future(module_id, False)
                return

            # Update status
            self.module_statuses[module_id] = ModuleStatus.ADAPTING

            # Integrate module
            success = self.integrator.integrate_module(
                module_data['metadata'].module_name,
                module_data['code'],
                module_data['metadata']
            )

            if success:
                self.module_statuses[module_id] = ModuleStatus.INTEGRATED
                del self.pending_modules[module_id]
                self.logger.info(f"Successfully processed module {module_id}")
                self._complete_integration_future(module_id, True)
            else:
                self.module_statuses[module_id] = ModuleStatus.FAILED
                self._complete_integration_future(module_id, False)

        except Exception as e:
            self.logger.error(f"Error processing module {module_id}: {e}")
            self.module_statuses[module_id] = ModuleStatus.FAILED
            self._complete_integration_future(module_id, False)

    def _complete_integration_future(self, module_id: str, success: bool):
        """Complete integration future if it exists"""
        if module_id in self.integration_futures:
            future = self.integration_futures[module_id]
            if not future.done():
                future.set_result(success)
            del self.integration_futures[module_id]

    def _check_unused_modules(self):
        """Check for unused modules and mark them as UNUSED"""
        current_time = time.time()

        if current_time - self.last_usage_check >= self.usage_check_interval:
            for module_name, module_data in self.sovereign_core.runtime_modules.items():
                usage_stats = module_data['usage_stats']

                # Check if module hasn't been used in 10 minutes
                if (usage_stats['call_count'] == 0 and 
                    current_time - usage_stats['integrated_at'] >= 600):
                    self.logger.info(f"Marking module {module_name} as UNUSED")
                    # Find module_id for this module
                    for mid, status in self.module_statuses.items():
                        if status == ModuleStatus.INTEGRATED:
                            # This is a simple way to mark unused modules
                            self.module_statuses[mid] = ModuleStatus.UNUSED
                            break

            self.last_usage_check = current_time

    def _cleanup_unused_modules(self):
        """Clean up unused modules"""
        unused_modules = []

        for module_name, module_data in list(self.sovereign_core.runtime_modules.items()):
            # Check if module is marked as unused
            for module_id, status in self.module_statuses.items():
                if status == ModuleStatus.UNUSED:
                    unused_modules.append(module_name)
                    break

        for module_name in unused_modules:
            self.logger.info(f"Cleaning up unused module: {module_name}")

            # Remove from runtime modules
            if module_name in self.sovereign_core.runtime_modules:
                del self.sovereign_core.runtime_modules[module_name]

            # Remove exposed functions
            for attr_name in list(dir(self.sovereign_core)):
                if attr_name.startswith(f"{module_name}_"):
                    delattr(self.sovereign_core, attr_name)

    def _evolve_existing_modules(self):
        """Evolve existing modules based on usage patterns"""
        for module_name, module_data in self.sovereign_core.runtime_modules.items():
            usage_stats = module_data['usage_stats']

            # Check if module needs evolution
            if (usage_stats['call_count'] > 50 and 
                time.time() - usage_stats.get('last_evolved', 0) > 3600):  # Evolve once per hour

                enhanced_code = self.evolver.enhance_module(module_name, usage_stats)
                if enhanced_code:
                    self._replace_evolved_module(module_name, enhanced_code, module_data)
                    usage_stats['last_evolved'] = time.time()

    def _evolve_specific_module(self, module_name: str):
        """Evolve a specific module on demand"""
        if module_name in self.sovereign_core.runtime_modules:
            module_data = self.sovereign_core.runtime_modules[module_name]
            usage_stats = module_data['usage_stats']

            enhanced_code = self.evolver.enhance_module(module_name, usage_stats)
            if enhanced_code:
                self._replace_evolved_module(module_name, enhanced_code, module_data)
                usage_stats['last_evolved'] = time.time()
                self.logger.info(f"Evolved module {module_name} on demand")

    def _replace_evolved_module(self, module_name: str, enhanced_code: str, old_module_data: Dict):
        """Replace old module with evolved version"""
        try:
            # Create new metadata
            new_metadata = old_module_data['metadata']
            new_metadata.version = f"{new_metadata.version}.enhanced"
            new_metadata.checksum = hashlib.md5(enhanced_code.encode()).hexdigest()

            # Remove old module functions
            for attr_name in list(dir(self.sovereign_core)):
                if attr_name.startswith(f"{module_name}_"):
                    delattr(self.sovereign_core, attr_name)

            # Preserve usage stats
            old_usage_stats = old_module_data['usage_stats']

            # Re-integrate enhanced module
            success = self.integrator.integrate_module(
                module_name,
                enhanced_code,
                new_metadata
            )

            if success:
