# Self-Healing Mechanism for Module Integrity

import hashlib
import os

class SelfHealingModule:
    def __init__(self, monitored_files, backup_dir="backup"):
        self.monitored_files = monitored_files
        self.backup_dir = backup_dir
        self.file_hashes = {}

    def calculate_hash(self, file_path):
        hasher = hashlib.sha256()
        try:
            with open(file_path, 'rb') as f:
                buf = f.read()
                hasher.update(buf)
            return hasher.hexdigest()
        except IOError:
            return None

    def load_hashes(self):
        for file in self.monitored_files:
            h = self.calculate_hash(file)
            if h:
                self.file_hashes[file] = h

    def verify_and_repair(self):
        for file in self.monitored_files:
            current_hash = self.calculate_hash(file)
            original_hash = self.file_hashes.get(file)
            if current_hash != original_hash:
                print(f"[SelfHealingModule] Integrity check failed for {file}. Attempting repair.")
                self.repair(file)
            else:
                print(f"[SelfHealingModule] Integrity check passed for {file}.")

    def repair(self, file):
        backup_path = os.path.join(self.backup_dir, os.path.basename(file))
        try:
            if os.path.exists(backup_path):
                with open(backup_path, 'rb') as src, open(file, 'wb') as dst:
                    dst.write(src.read())
                print(f"[SelfHealingModule] Repaired {file} from backup.")
                # Update hash after repair
                self.file_hashes[file] = self.calculate_hash(file)
            else:
                print(f"[SelfHealingModule] Backup not found for {file}, cannot repair.")
        except IOError as e:
            print(f"[SelfHealingModule] Repair failed for {file}: {e}")

