        self.channels[channel_name] = handler
        self.message_queues[channel_name] = queue.Queue()
        threading.Thread(target=self._process_queue, args=(channel_name,), daemon=True).start()
        print(f"[CommunicationDispatcher] Channel '{channel_name}' registered.")

