class PromptManager:
    def __init__(self, max_tokens=2048):
        self.max_tokens = max_tokens
        self.history = []

    def add_user_input(self, text):
        self.history.append(("user", text))
        self._trim_history()

    def add_model_response(self, text):
        self.history.append(("model", text))
        self._trim_history()

    def _trim_history(self):
        # Naive token count limit enforcement
        token_count = sum(len(entry[1].split()) for entry in self.history)
        while token_count > self.max_tokens:
            self.history.pop(0)
            token_count = sum(len(entry[1].split()) for entry in self.history)

    def build_prompt(self):
        prompt = ""
        for role, text in self.history:
            prefix = "User: " if role == "user" else "Model: "
            prompt += f"{prefix}{text}\n"
        prompt += "Model: "
        return prompt

class LanguageModelEngine:
